:root {
  --bg: #0f172a;
  --card: rgba(255, 255, 255, 0.03);
  --border: rgba(255, 255, 255, 0.1);
  --accent: #3b82f6;
  --text: #f8fafc;
  --text-dim: #94a3b8;
}

body {
  background: transparent;
  color: var(--text);
  font-family: "Inter", sans-serif;
  margin: 0;
}

.gst-container {
  padding: 24px;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 16px;
  box-shadow: 0 20px 50px rgba(0, 0, 0, 0.5);
  display: flex;
  flex-direction: column;
  min-height: 500px;
}

.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
}

.stats-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr; /* Force 3 columns */
  gap: 16px;
  margin-bottom: 24px;
}

.stat-card {
  padding: 16px;
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 12px;
}

.stat-card.highlight {
  border-left: 4px solid var(--accent);
}

.stat-card label {
  font-size: 11px;
  color: var(--text-dim);
  text-transform: uppercase;
  font-weight: 600;
}

.stat-card .value {
  font-size: 20px;
  font-weight: 700;
  margin: 6px 0;
}

.stat-card .sub-text {
  font-size: 11px;
  color: var(--text-dim);
}

.tabs-nav {
  display: flex;
  gap: 8px;
  margin-bottom: 16px;
  border-bottom: 1px solid var(--border);
  padding-bottom: 10px;
}

.tab-link {
  background: transparent;
  border: none;
  color: var(--text-dim);
  padding: 6px 14px;
  cursor: pointer;
  font-size: 13px;
  border-radius: 6px;
}

.tab-link.active {
  background: rgba(59, 130, 246, 0.15);
  color: var(--accent);
  font-weight: 600;
}

.primary-btn {
  background: var(--accent);
  color: white;
  border: none;
  padding: 8px 20px;
  border-radius: 8px;
  font-weight: 600;
  cursor: pointer;
}

.table-preview {
  flex: 1;
  overflow-y: auto;
  border-radius: 8px;
  background: rgba(0, 0, 0, 0.2);
}

table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}

th {
  text-align: left;
  padding: 12px;
  border-bottom: 1px solid var(--border);
  color: var(--text-dim);
  position: sticky;
  top: 0;
  background: #1e293b;
}

td {
  padding: 12px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.03);
}

